<template lang="en">
<div>
    <loader :is-visible="isLoading"></loader>
    <section class="main-content">
        <div ref="hellp" id="divMaindealData">
            <div class="border p-3">
                <Form ref="JobPostForm">
                    <dynamic-form lang="en" ref="BarcodeReport" v-if="DataLoaded" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit"></dynamic-form>
                    <div class="row placeholder">
                        <div class="col-md-12 p-0">
                            <ReportViewer v-if="parameter.length > 0" :key="loadKey" :viewerId="'viewer_' + loadKey" :parameter="parameter" :reportPath="reportPath">
                            </ReportViewer>
                        </div>
                    </div>
                </Form>
            </div>
        </div>
    </section>
</div>
</template>

<script>
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-designer.min';
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-viewer.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.bulletgraph.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.chart.min';
import DataServices from "../../services/DataService";
import ReportViewer from '../../views/HrReport/ReportViewer.vue';
import { locateBillingService } from "../../services/locateBillingService";
export default {
    components: {
        ReportViewer
    },
    data() {
        return {
            isLoading: false,
            reportPath: null,
            parameter: [],
            loadKey: 0,
            ClientData: [],
            currentReportParams: null,
            FormSchema: [{
                layoutType: "triple",
                Data: [{
                    astype: "SearchableSelectField",
                    label: this.$t('CONTRACTNAME'),
                    name: "ContractName",
                    value: "",
                    placeholder: this.$t('SelectClient'),
                    visibility: true,
                    isSearch: true,
                    config: {
                        options: [],
                        actionButtons: {
                            selectAll: true,
                            active: true,
                            inactive: true,
                            clear: true
                        },
                        itemFields: ['text', 'status'],
                        isMultiple: true,
                        groupFields: ['groupText'],
                        minSearchLength: 0,
                        statusFieldConfig: {
                            fieldName: 'status',
                            activeValues: ['Active', 'active'],
                            inactiveValues: ['Inactive', 'inactive'],
                            activeColor: '#28a745',
                            inactiveColor: '#dc3545'
                        },
                        onChange: this.onSelectionChange
                    },
                    validationRules: {
                        "required": false
                    },
                },
                {
                    astype: "SearchableSelectField",
                    label: this.$t('BillingRuleName'),
                    name: "BillingRule",
                    value: "",
                    placeholder: this.$t('Select') + " " + this.$t('BillingRule'),
                    visibility: true,
                    isSearch: false,
                    config: {
                        options: [],
                        actionButtons: {
                            selectAll: true,
                            clear: true
                        },
                        groupFields: [],
                        isMultiple: true,
                        minSearchLength: 0,
                        statusFieldConfig: {
                            fieldName: 'status',
                            activeValues: ['Active', 'active'],
                            inactiveValues: ['Inactive', 'inactive'],
                            activeColor: '#28a745',
                            inactiveColor: '#dc3545'
                        },
                    },
                    validationRules: {
                        "required": false
                    },
                },
                {
                    astype: "SearchableSelectField",
                    label: this.$t("Billing Rule Status"),
                    name: "Status",
                    value: "",
                    placeholder: this.$t('Select') + " " + this.$t('Billing Rule Status'),
                    visibility: true,
                    isSearch: false,
                    config: {
                        options: [],
                        isMultiple: false,
                        groupFields: [],
                        minSearchLength: 0,
                        actionButtons: {
                            clear: true
                        },
                        statusFieldConfig: {
                            fieldName: 'status',
                            activeValues: ['Active', '1001'],
                            inactiveValues: ['Inactive', '1002'],
                            activeColor: '#28a745',
                            inactiveColor: '#dc3545'
                        }
                    },
                    validationRules: {
                        required: false
                    }
                },
                {
                    astype: "SearchableSelectField",
                    label: this.$t('Biller'),
                    name: "Biller",
                    value: "",
                    placeholder: this.$t('Select') + " " + this.$t('Biller'),
                    visibility: false,
                    isSearch: true,
                    config: {
                        options: [],
                        actionButtons: {
                            selectAll: true,
                            active: false,
                            inactive: false,
                            clear: true
                        },
                        itemFields: ['text', 'status'],
                        isMultiple: true,
                        groupFields: [],
                        minSearchLength: 0,
                        statusFieldConfig: {
                            fieldName: 'status',
                            activeValues: ['Active', 'active'],
                            inactiveValues: ['Inactive', 'inactive'],
                            activeColor: '#28a745',
                            inactiveColor: '#dc3545'
                        }
                    },
                    validationRules: {
                        "required": false
                    },
                },
                ]
            }],
            buttons: [{
                type: "submit",
                class: "btn btn-success",
                text: "<i class='fa fa-search pr-2'></i>Search",
            },
            {
                type: "button",
                class: "btn btn-danger",
                text: "<i class='fa fa-close pr-2'></i>Clear all",
                onClick: this.ClearAll
            },
            ],
            DataLoaded: 0,
        };
    },
    mounted() {
        window.handleExceededLink = () => {
            this.saveReportRequest();
        };
    },
    beforeDestroy() {
        delete window.handleExceededLink;
    },
    created: async function () {
        var vm = this;
        vm.userId = vm.GetUserInfo.ID;
        vm.companyId = vm.GetUserInfo.CompanyId;
        vm.UserType = vm.GetUserInfo.UserType;
        vm.DataLoaded = 1;
        await vm.GetStatusList();
        await vm.fetchclientlist();
        await vm.GetBillerList()
        await vm.GetEmailConfigurationSetting();
    },
    methods: {
        async onSubmit(e) {
            var vm = this;
            vm.isLoading = true;
            vm.loadKey = Date.now();
            vm.reportPath = '';
            vm.parameter = [];

            let myObj = {
                reportName: "billingrulereport",
                BillingRuleId: e.BillingRule.length > 0 ? e.BillingRule.join(",") : '',
                ClientIds: e.ContractName.length > 0 ? e.ContractName.join(",") : '',
                RuleStatus: e.Status, 
                BillerIds: e.Biller && e.Biller.length > 0 ? e.Biller.join(",") : ''                  
            }
            vm.currentReportParams = myObj;
            var postString = JSON.stringify(myObj);
            DataServices.ReportMain(postString).then(function (response) {
                vm.reportPath = response.data.reportpath;
                vm.parameter = response.data.parameters;
                vm.isLoading = false;
            }).catch(function (error) {
                console.error("Error loading report:", error);
                vm.isLoading = false;
            });
        },
        ClearAll: function () {
            var vm = this;
            (vm.FormSchema)[0].Data[0].value = '';
            (vm.FormSchema)[0].Data[1].value = '';
            (vm.FormSchema)[0].Data[2].value = '';
             (vm.FormSchema)[0].Data[3].value = '';
            vm.reportPath = '';
            vm.parameter = [];
            vm.loadKey = 0;
            vm.currentReportParams = null;
            vm.$refs.BarcodeReport.validateForm.reset();
        },
        fetchclientlist: async function () {
            var vm = this;
            vm.isLoading = true;
            var url = `reqFrom=CUSTOMREPORT`;
            await locateBillingService.getClientList(url).then(response => {
                vm.isLoading = false;
                vm.ClientData = response.data.items;
                vm.$refs.BarcodeReport.updateProperty("ContractName", "config.options", vm.ClientData);
                vm.$refs.BarcodeReport.UpdateKeyValue();

            }).catch(error => {
                vm.isLoading = false;
                vm.ClientData = [];
                vm.$refs.BarcodeReport.updateProperty("ContractName", "config.options", vm.ClientData);
                vm.$refs.BarcodeReport.UpdateKeyValue();
                console.error('Error fetching client list:', error);
            }).finally(() => {
                vm.isLoading = false;
            });
        },
         async GetEmailConfigurationSetting() {
            var vm = this;
            var params = `companyId=${vm.companyId}&userId=${vm.userId}&moduleName=User&configkey=CanViewAllContractData`;
            await locateBillingService.GetEmailConfigurationSetting(params).then(response => {
                const value = response.data?.[0]?.CONFIG_DATA_VALUE;                
                vm.canViewAllContractData = value && value.toLowerCase() === 'yes';
                vm.canViewAllContractDataString = value;                 
                vm.hasAccess = (
                    vm.isSupervisor === true ||
                    vm.GetUserInfo?.UserType === "CA" ||
                    vm.canViewAllContractData === true || 
                    (vm.canViewAllContractDataString && 
                    vm.canViewAllContractDataString.toLowerCase() === "yes") 
                );
                if (vm.hasAccess) {
                   (vm.FormSchema)[0].Data[3].visibility = true;
                }
            })
            .catch(err => {
                console.error("GetEmailConfigurationSetting error:", err);
            });
        },
         GetBillerList: async function () {
            var vm = this;
            var params = `reqFrom=all&moduleName=Billing`;
            await locateBillingService.GetBillerList(params).then((response) => {
                let SelectedBillerList = [];
                var BillerList = JSON.parse(response.data.result);
                if (BillerList != null) {
                    BillerList.forEach(item => {
                        let obj = {
                            description: null,
                            displayValue: item.USERNAME,
                            groupText: null,
                            groupValue: null,
                            metaData: null,
                            text: item.USERNAME,
                            value: item.USERID
                        };
                        SelectedBillerList.push(obj);
                    });
                    vm.$refs.BarcodeReport.updateProperty("Biller", "config.options", SelectedBillerList);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            });
        },
        async onSelectionChange(value, x) {
            var vm = this;
            vm.isLoading = true;
             if (x && x.length > 0) {
                vm.selectedClientId = x;
                vm.clientId = x;
            } else {
                vm.selectedClientId = null;
                vm.clientId = null;
                vm.$refs.BarcodeReport.updateProperty("BillingRule", "config.options", []);
                vm.$refs.BarcodeReport.updateProperty("BillingRule", "value", '');
            }
            var url = `ClientId=${vm.clientId}`;
            await DataServices.GetBillingRuleListByContractId(url).then(response => {
                let SelectedBillingRuleList = [];
                var BillingRuleList = response.data;
                if (BillingRuleList != null) {
                    BillingRuleList.forEach(item => {
                        let obj = {
                            description: null,
                            displayValue: item.BILLINGRULE,
                            groupText: null,
                            groupValue: null,
                            metaData: null,
                            text: item.BILLINGRULE,
                            value: item.BILLINGRULE_ID
                        };
                        SelectedBillingRuleList.push(obj);
                    });
                    vm.$refs.BarcodeReport.updateProperty("BillingRule", "config.options", SelectedBillingRuleList);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            }).catch(error => {
                vm.isLoading = false;
                vm.SelectedBillingRuleList = [];
                vm.$refs.BarcodeReport.updateProperty("BillingRule", "config.options", []);
                vm.$refs.BarcodeReport.updateProperty("BillingRule", "value", '');
            }).finally(() => {
                vm.isLoading = false;
            });
        },
        GetStatusList: async function () {
            var vm = this;
            var url = `langCode=en&statusType=ContractStatus&hasglobal=1`
            await DataServices.GetStatusList(url).then((response) => {
                let SelectedStatusList = [];
                if (response.data.length > 0) {
                    const StatusData = response.data.filter(
                        item => item.STATUS_ID === 1001 || item.STATUS_ID === 1002
                    );
                    StatusData.forEach(item => {
                        let obj = {
                            description: null,
                            displayValue: item.STATUS,
                            groupText: null,
                            groupValue: null,
                            metaData: null,
                            text: item.STATUS,
                            value: item.STATUS_ID
                        };
                        SelectedStatusList.push(obj);
                    });
                    vm.$refs.BarcodeReport.updateProperty("Status", "config.options", SelectedStatusList);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            });
        },
        async saveReportRequest() {
            var vm = this;
            vm.isLoading = true;
            try {
                if (!vm.currentReportParams) {
                    console.error('No report parameters available. Please generate a report first.');
                    return;
                }

                const params = {
                    reportName: vm.currentReportParams.reportName || 'billingrulereport',
                    hdnClientId: vm.currentReportParams.ClientIds || '',
                    startDate: vm.currentReportParams.dateFrom || '',
                    endDate: vm.currentReportParams.dateTo || '',
                    DivisionInvoiceFrequency: vm.currentReportParams.Frequency || '',
                    hdnStatusId: vm.currentReportParams.Status || '',
                    hdnState: vm.currentReportParams.State || '',
                    UtilityNames: vm.currentReportParams.UtilityName || '',
                    DivisionNames: vm.currentReportParams.Invoicegrouping || '',
                    ProcessFromDate: vm.currentReportParams.ProccessFromDate || '',
                    ProcessToDate: vm.currentReportParams.ProccessToDate || '',
                    Workcode: vm.currentReportParams.Workcode || '',
                     BillerIds: e.Biller && e.Biller.length > 0 ? e.Biller.join(",") : ''  
                };

                console.log('Saving report request with params:', params);

                let response = await DataServices.SaveReportRequest(params);
                if (response.data && response.data.result === 'success') {
                    vm.ShowAlert("Request submitted successfully", "success", true, vm.$t("Alert"));
                } else {
                    vm.ShowAlert("We couldn't submit your request. Please try again.", "failure", true, vm.$t("Alert"));
                }
            } catch (error) {
                console.error('Error saving report request:', error);
            } finally {
                vm.isLoading = false;
            }
        }
    }
};
</script>